class Solution:
    def minArraySum(self, nums, k, op1, op2):
        n = len(nums)
        best = [float('inf')]

        def dfs(i, o1, o2, total):
            if total >= best[0]:
                return
            if i == n:
                best[0] = min(best[0], total)
                return
            v = nums[i]
            dfs(i + 1, o1, o2, total + v)
            if o1 > 0:
                dfs(i + 1, o1 - 1, o2, total + -(-v // 2))
            if o2 > 0 and v >= k:
                dfs(i + 1, o1, o2 - 1, total + (v - k))
            if o1 > 0 and o2 > 0:
                half = -(-v // 2)
                if half >= k:
                    dfs(i + 1, o1 - 1, o2 - 1, total + half - k)
                if v >= k:
                    dfs(i + 1, o1 - 1, o2 - 1, total + -(-(v - k) // 2))

        dfs(0, op1, op2, 0)
        return best[0]

