class Solution:
    def minArraySum(self, nums, k, op1, op2):
        n = len(nums)
        dp = [[0] * (op2 + 1) for _ in range(op1 + 1)]
        for i in range(n - 1, -1, -1):
            v = nums[i]
            new_dp = [[0] * (op2 + 1) for _ in range(op1 + 1)]
            for o1 in range(op1 + 1):
                for o2 in range(op2 + 1):
                    best = v + dp[o1][o2]
                    if o1 > 0:
                        cand = -(-v // 2) + dp[o1 - 1][o2]
                        if cand < best:
                            best = cand
                    if o2 > 0 and v >= k:
                        cand = (v - k) + dp[o1][o2 - 1]
                        if cand < best:
                            best = cand
                    if o1 > 0 and o2 > 0:
                        options = []
                        half = -(-v // 2)
                        if half >= k:
                            options.append(half - k)
                        if v >= k:
                            options.append(-(-(v - k) // 2))
                        if options:
                            cand = min(options) + dp[o1 - 1][o2 - 1]
                            if cand < best:
                                best = cand
                    new_dp[o1][o2] = best
            dp = new_dp
        return dp[op1][op2]

