var minArraySum = function(nums, k, op1, op2) {
    const n = nums.length;
    let dp = Array.from({ length: op1 + 1 }, () => new Array(op2 + 1).fill(0));
    for (let i = n - 1; i >= 0; i--) {
        const v = nums[i];
        const newDp = Array.from({ length: op1 + 1 }, () => new Array(op2 + 1).fill(0));
        for (let o1 = 0; o1 <= op1; o1++) {
            for (let o2 = 0; o2 <= op2; o2++) {
                let best = v + dp[o1][o2];
                if (o1 > 0) {
                    const cand = Math.ceil(v / 2) + dp[o1 - 1][o2];
                    if (cand < best) best = cand;
                }
                if (o2 > 0 && v >= k) {
                    const cand = (v - k) + dp[o1][o2 - 1];
                    if (cand < best) best = cand;
                }
                if (o1 > 0 && o2 > 0) {
                    const options = [];
                    const half = Math.ceil(v / 2);
                    if (half >= k) options.push(half - k);
                    if (v >= k) options.push(Math.ceil((v - k) / 2));
                    if (options.length) {
                        const cand = Math.min(...options) + dp[o1 - 1][o2 - 1];
                        if (cand < best) best = cand;
                    }
                }
                newDp[o1][o2] = best;
            }
        }
        dp = newDp;
    }
    return dp[op1][op2];
};
